import { AutoComplete } from "primereact/autocomplete";
import React from "react";
import KitsContainer from "../../helpers/FormContainer";
import { useSeparator } from "../../../factory";
import type { IAutoCompleteElement } from "@lmb-it/kitsconcerto-types";
import { useKitsTheme } from "../../../contexts/Theme";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useAutoCompleteLogic } from "../hooks/useAutoCompleteLogic";

const KitsAutoComplete = ({ ref, ...rawProps }: IAutoCompleteElement) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('AutoComplete', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        label,
        hideError,
        disabled,
        required,
        isFloatedLabel,
        inputSize = "md",
        forceSelection,
        completeMethod,
        helperText,
        withArrow,
        placeholder,
        isMultiple,
        localProps,
        delay,
        minLength,
        selectionLimit,
        showEmptyMessage,
        attached,
        containerStyle,
    } = props;

    const { nativeProps } = useSeparator<HTMLSelectElement>(props);

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    const {
        inputValue,
        setInputValue,
        filteredList,
        search,
        handleOnChange,
        list,
        childrenKey,
        labelKey,
    } = useAutoCompleteLogic({ isMultiple, forceSelection, completeMethod, ref });

    const Element = <AutoComplete
        className={`w-full ${nativeProps.className ?? ""}`}
        disabled={disabled}
        placeholder={placeholder}
        value={inputValue}
        forceSelection={forceSelection}
        suggestions={Array.isArray(filteredList) ? filteredList : list}
        completeMethod={search}
        dropdown={withArrow}
        multiple={isMultiple}
        field={labelKey}
        showEmptyMessage={showEmptyMessage ?? true}
        emptyMessage="No results found"
        {...(delay != null ? { delay } : {})}
        {...(minLength != null ? { minLength } : {})}
        {...(selectionLimit != null ? { selectionLimit } : {})}
        inputStyle={{ width: "100%", borderRadius: 0, border:'none', backgroundColor:'transparent' }}
        style={{ flexDirection: "row", borderRadius: 0, border:'none', width: "100%",backgroundColor:'transparent', ...(resolvedRootStyle || resolvedThemeStyle) }}
        pt={{
            container:{
                style:{
                    backgroundColor:'transparent',
                    border:'none'
                }
            },
            item: ({ context }: any) => context?.selected ? {
                style: { backgroundColor: primaryColor, color: 'white' }
            } : context?.focused ? {
                style: { backgroundColor: `color-mix(in srgb, ${primaryColor} 12%, transparent)` }
            } : undefined,
            token: {
                style: {
                    backgroundColor: `color-mix(in srgb, ${primaryColor} 15%, transparent)`,
                    color: primaryColor,
                }
            },
        }}
        optionGroupChildren={childrenKey ?? undefined}
        optionGroupLabel={childrenKey ? labelKey : undefined}
        onChange={(event) => {
            setInputValue(event.value);
            handleOnChange(event);
        }}
        onSelect={(event) => {
            handleOnChange(
                { originalEvent: event.originalEvent, value: event.value },
            );
        }}
        aria-label="List"
        {...(localProps ? localProps : {})}
        dropdownAriaLabel="Select Item"
    />;

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            hideError={hideError}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsAutoComplete;
